import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        char[] buffer = new char[10];
        int length = Math.min(input.length(), buffer.length);

        for (int i = 0; i < length; i++) {
            // Ensure that the input is within ASCII printable characters range
            if (input.charAt(i) >= 32 && input.charAt(i) <= 126) {
                buffer[i] = input.charAt(i);
            } else {
                // If a non-printable character is encountered, replace it with a default character
                buffer[i] = '*';
            }
        }

        System.out.println("Buffer content: " + new String(buffer));
    }
}

